/* Color palette: red (#ff0000), black (#000000), white (#ffffff) */
:root {
  --red: #ff0000;
  --black: #000000;
  --white: #ffffff;
}

* { box-sizing: border-box; }
html, body { height: 100%; }

body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Arial, sans-serif;
  color: var(--black);
  background: var(--white);
  line-height: 1.6;
  font-size: 16px;
}

img { max-width: 100%; height: auto; display: block; }

.container { width: min(960px, 92%); margin: 0 auto; }

.hero {
  background: var(--black);
  color: var(--white);
  padding: 4rem 0;
  text-align: center;
  border-bottom: 4px solid var(--red);
}
.hero .subtitle { margin-top: .5rem; opacity: .9; }

.btn {
  display: inline-block;
  margin-top: 1rem;
  background: var(--red);
  color: var(--white);
  border: none;
  padding: .75rem 1.25rem;
  text-decoration: none;
  font-weight: 600;
  border-radius: 4px;
}
.btn:hover, .btn:focus { filter: brightness(0.9); }

main { padding: 2rem 0; }

h2 { border-left: 6px solid var(--red); padding-left: .5rem; margin-top: 0; }
.intro { margin-top: .25rem; }

.services {
  list-style: none;
  padding: 0;
  margin: 1rem 0;
  display: grid;
  grid-template-columns: 1fr;
  gap: .5rem;
}
.services li {
  background: var(--white);
  border: 1px solid var(--black);
  padding: .75rem;
  border-left: 4px solid var(--red);
}

.field { margin-bottom: 1rem; }
label { display: block; margin-bottom: .25rem; font-weight: 600; }
input, textarea {
  width: 100%;
  padding: .65rem .75rem;
  border: 1px solid var(--black);
  border-radius: 4px;
  background: var(--white);
  color: var(--black);
}

.site-footer {
  background: var(--black);
  color: var(--white);
  padding: 1rem 0;
  text-align: center;
  border-top: 4px solid var(--red);
}

@media (min-width: 640px) {
  .services { grid-template-columns: repeat(2, 1fr); }
}

@media (prefers-reduced-motion: reduce) {
  * { transition: none !important; }
}

document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('contact-form');
  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const nameEl = document.getElementById('name');
      const nameVal = nameEl && 'value' in nameEl ? String(nameEl.value).trim() : '';
      alert(`Thank you${nameVal ? ', ' + nameVal : ''}! Your message has been received.`);
      if (typeof form.reset === 'function') form.reset();
    });
  }

  const yearEl = document.getElementById('year');
  if (yearEl) {
    yearEl.textContent = String(new Date().getFullYear());
  }
});

