const fs = require('fs');
const path = require('path');

describe('index.html', () => {
  test('contains the exact hero title text', () => {
    const htmlPath = path.join(__dirname, '..', 'index.html');
    const html = fs.readFileSync(htmlPath, 'utf8');
    expect(html).toContain('Professional Lab Technician');
  });
});
